{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日（2026年5月13日）をもって正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "毎週水曜日の10時から週次定例会議を開催する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "データ移行では、第1フェーズでマスタ系のみを移行し、トランザクション履歴は旧システムを参照用に残す。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "サクラ商事さんとの共同利用（第3案）で認証とマスタ配信の共通基盤を進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "外部ライセンス費用について、単月契約および年契約の条件を含めて再見積もりを行う。",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D6",
      "content": "新システムでのユーザー権限は既存のロール定義を流用し、新規設計は行わない。",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D7",
      "content": "本番リリース目標日付を9月末から10月15日に延期する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "移行方式は拠点を分けて段階的に切り替える方法を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "システム切り替え作業は土曜日の深夜帯に行う。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "障害発生時の一次受け窓口をQAチームに変更する。",
      "decided_by": "桐生 遥"
    }
  ],
